SELECT school_id, COUNT(data_set_id) AS data_set_count
FROM data_sets
GROUP BY school_id;

SELECT AVG(data_value) AS average_grade
FROM data_details
WHERE subject_id = 0 AND grade_id = 1;

SELECT SUM(file_size) AS total_file_size, year
FROM data_sets
WHERE year = 2023;

SELECT AVG(data_value) AS average_data_value
FROM data_details
WHERE demographic_id = 1;
